import React, { useState, useEffect } from 'react';
import { ICEBREAKERS } from '../../data';
import { useLocalStorage } from '../../hooks';
import { C } from '../../utils/theme';

const CATS = [
  { id:'divertidas', name:'Divertidas', emoji:'😄', color:'#FFE4A0' },
  { id:'profundas',  name:'Profundas',  emoji:'💭', color:'#C5B8E8' },
  { id:'romanticas', name:'Románticas', emoji:'💕', color:'#FFB3C1' },
  { id:'retos',      name:'Retos',      emoji:'🔥', color:'#FFB085' },
];

export default function IcebreakerPage() {
  const [cat, setCat]         = useState('divertidas');
  const [question, setQ]      = useState(null);
  const [spinning, setSpin]   = useState(false);
  const [history, setHist]    = useState([]);
  const [custom, setCustom]   = useLocalStorage('spindocky-icebreakers', { divertidas:[], profundas:[], romanticas:[], retos:[] });
  const [showAdd, setShowAdd] = useState(false);
  const [newQ, setNewQ]       = useState('');

  const current = CATS.find(c => c.id === cat);
  const allQuestions = [...ICEBREAKERS[cat], ...(custom[cat] || [])];

  const spin = () => {
    setSpin(true); setQ(null);
    setTimeout(() => {
      const avail = allQuestions.filter(q => !history.slice(-allQuestions.length + 1).includes(q));
      const src = avail.length > 0 ? avail : allQuestions;
      const q = src[Math.floor(Math.random() * src.length)];
      setQ(q); setHist(h => [...h, q]); setSpin(false);
    }, 800);
  };

  const addQuestion = () => {
    if (!newQ.trim()) return;
    setCustom(prev => ({ ...prev, [cat]: [...(prev[cat] || []), newQ.trim()] }));
    setNewQ(''); setShowAdd(false);
  };

  const removeCustomQ = (idx) => {
    setCustom(prev => ({ ...prev, [cat]: prev[cat].filter((_, i) => i !== idx) }));
  };

  return (
    <div style={{ height:'100%', display:'flex', flexDirection:'column', gap:12 }}>
      {/* Header */}
      <div className="card-ink" style={{ padding:'14px 18px', flexShrink:0 }}>
        <div style={{ fontFamily:'Fredoka One', fontSize:20, color:C.ink }}>💬 Rompehielos</div>
        <p style={{ fontFamily:'Nunito', fontSize:12, color:'#888', marginTop:2 }}>Preguntas y retos para conocerse mejor ✨</p>
      </div>

      {/* Category tabs */}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, flexShrink:0 }}>
        {CATS.map(c => (
          <button key={c.id} onClick={() => { setCat(c.id); setQ(null); setShowAdd(false); }}
            style={{ background:cat===c.id?c.color:'#fff', border:`2.5px solid ${cat===c.id?C.ink:C.grayLt}`, borderRadius:14, padding:'10px 12px', fontFamily:'Nunito', fontWeight:800, fontSize:13, color:C.ink, cursor:'pointer', textAlign:'left', boxShadow:cat===c.id?`0 3px 0 ${C.ink}`:`0 2px 0 ${C.grayLt}`, transition:'all 0.15s' }}>
            <span style={{ fontSize:20, display:'block', marginBottom:2 }}>{c.emoji}</span>
            {c.name}
            {(custom[c.id]||[]).length > 0 && (
              <span style={{ fontFamily:'Nunito', fontSize:10, fontWeight:700, color:C.gray, marginLeft:4 }}>+{custom[c.id].length}</span>
            )}
          </button>
        ))}
      </div>

      {/* Docky + question */}
      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:14 }}>
        <div style={{ width:72, height:72, background:'#7EC8E3', border:'3px solid #1A1A1A', borderRadius:22, display:'flex', alignItems:'center', justifyContent:'center', fontSize:40, boxShadow:'0 5px 0 #1A1A1A', animation:spinning?'spin360 0.8s linear':'float 3s ease-in-out infinite' }}>
          🐾
        </div>

        {question ? (
          <div style={{ background:current.color, border:'3px solid #1A1A1A', borderRadius:22, padding:'20px 22px', textAlign:'center', boxShadow:'0 5px 0 #1A1A1A', maxWidth:360, width:'100%', animation:'popIn 0.4s cubic-bezier(0.34,1.56,0.64,1) both' }}>
            <div style={{ fontSize:26, marginBottom:8 }}>{current.emoji}</div>
            <div style={{ fontFamily:'Fredoka One', fontSize:18, color:C.ink, lineHeight:1.4 }}>{question}</div>
          </div>
        ) : (
          <div style={{ border:`2px dashed ${C.grayLt}`, borderRadius:22, padding:'24px', textAlign:'center', maxWidth:360, width:'100%' }}>
            <div style={{ fontFamily:'Fredoka One', fontSize:16, color:'#C8C0B4' }}>
              {spinning ? '✨ Eligiendo pregunta...' : 'Presiona para una pregunta 👆'}
            </div>
          </div>
        )}

        <div style={{ display:'flex', gap:8, maxWidth:360, width:'100%' }}>
          <button className="btn3d" onClick={spin} disabled={spinning}
            style={{ flex:1, background:current.color, color:C.ink, fontSize:15, padding:'11px 16px' }}>
            {spinning ? '🌀 Eligiendo...' : `${current.emoji} Nueva pregunta`}
          </button>
          <button className="btn3d" onClick={() => setShowAdd(p => !p)}
            title="Agregar pregunta personalizada"
            style={{ background:showAdd?C.ink:C.white, color:showAdd?C.white:C.ink, fontSize:16, padding:'11px 14px', width:46, borderColor:showAdd?C.ink:C.grayLt, boxShadow:showAdd?`0 3px 0 ${C.ink}`:`0 2px 0 ${C.grayLt}` }}>
            ✏️
          </button>
        </div>

        {/* Add question form */}
        {showAdd && (
          <div style={{ maxWidth:360, width:'100%', background:current.color+'44', border:`2px solid ${current.color}`, borderRadius:16, padding:'12px 14px', animation:'popIn 0.3s ease both' }}>
            <div style={{ fontFamily:'Nunito', fontWeight:800, fontSize:11, color:C.ink, marginBottom:8 }}>
              ✏️ Agregar pregunta a <strong>{current.name}</strong>
            </div>
            <div style={{ display:'flex', gap:6 }}>
              <input value={newQ} onChange={e => setNewQ(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && addQuestion()}
                placeholder="Escribe tu pregunta... (Enter)"
                style={{ flex:1, background:'white', border:`2px solid ${C.grayLt}`, borderRadius:10, fontSize:13, padding:'8px 11px' }}/>
              <button className="btn3d" onClick={addQuestion} disabled={!newQ.trim()}
                style={{ background:'#7EC8E3', color:C.ink, fontSize:13, padding:'8px 14px', borderRadius:20, boxShadow:`0 2px 0 ${C.ink}` }}>
                +
              </button>
            </div>

            {/* Custom questions list */}
            {(custom[cat] || []).length > 0 && (
              <div style={{ marginTop:10, display:'flex', flexDirection:'column', gap:4, maxHeight:100, overflowY:'auto' }}>
                <div style={{ fontFamily:'Nunito', fontWeight:900, fontSize:10, color:'#888', textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:2 }}>
                  Tus preguntas ({custom[cat].length})
                </div>
                {custom[cat].map((q, i) => (
                  <div key={i} style={{ background:'white', border:`1.5px solid ${C.grayLt}`, borderRadius:8, padding:'5px 9px', display:'flex', alignItems:'center', gap:6 }}>
                    <span style={{ fontFamily:'Nunito', fontSize:11, fontWeight:600, color:C.ink, flex:1, lineHeight:1.4 }}>{q}</span>
                    <button onClick={() => removeCustomQ(i)}
                      style={{ background:'transparent', border:'none', cursor:'pointer', color:'#DDD', fontSize:15, lineHeight:1, flexShrink:0, padding:2 }}
                      onMouseEnter={e => e.target.style.color='#FF6B6B'} onMouseLeave={e => e.target.style.color='#DDD'}>×</button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Last questions */}
      {history.length > 1 && (
        <div className="card" style={{ padding:'10px 14px', flexShrink:0 }}>
          <div style={{ fontFamily:'Nunito', fontWeight:900, fontSize:10, color:'#AAA', letterSpacing:'0.1em', textTransform:'uppercase', marginBottom:7 }}>Anteriores</div>
          {history.slice(-3).reverse().slice(1).map((q, i) => (
            <div key={i} style={{ fontFamily:'Nunito', fontSize:11, color:'#BBB', lineHeight:1.4, paddingBottom:3 }}>• {q}</div>
          ))}
        </div>
      )}
    </div>
  );
}
